class Solution:
    def findStrobogrammatic(self, n: int) -> list[str]:
        def _generate(length: int) -> list[str]:
            if length == 0:
                return [""]
            if length == 1:
                return ["0", "1", "8"]

            prev_results = _generate(length - 2)
            current_results = []

            for s in prev_results:
                current_results.append("1" + s + "1")
                current_results.append("6" + s + "9")
                current_results.append("8" + s + "8")
                current_results.append("9" + s + "6")
                current_results.append("0" + s + "0")

            return current_results

        if n == 0:
            return [""]
        if n == 1:
            return ["0", "1", "8"]

        inner_parts = _generate(n - 2)
        final_results = []

        for s in inner_parts:
            final_results.append("1" + s + "1")
            final_results.append("6" + s + "9")
            final_results.append("8" + s + "8")
            final_results.append("9" + s + "6")

        return final_results
